        consent_mock.upload_time = datetime.now()
        consent_mock.file_path = '/test'
        for method_name, return_value in consent_args.items():
            if hasattr(consent_mock, method_name):
                getattr(consent_mock, method_name).return_value = return_value
        return consent_mock

    def assertMatchesExpectedResults(self, expected_list, actual_list: List[ConsentFile]):
        self.assertEqual(len(expected_list), len(actual_list))

        def expected_data_found_in_results(expected_result):
            for actual_result in actual_list:
                if all([getattr(actual_result, attr_name) == value for attr_name, value in expected_result.items()]):
                    return True

            return False

        def json_print(data):
            return json.dumps(data, default=str, indent=4)

        for expected in expected_list:
            if not expected_data_found_in_results(expected):
                self.fail(
                    f'{json_print(expected)} not found in results: '
                    f'{json_print([actual.asdict() for actual in actual_list])}'
                )

import inspect

from server.customhttp import HTTPResponse


class NoSuchUrl(Exception):
    def __init__(self, url):
        self.url = url


class Dispatcher:
    def __init__(self, urls, scheduler, deque):
        self.deque = deque
        self.urls = urls
        self.scheduler = scheduler

    def dispatch(self, request):
        fun = self._pick_handler_function(request.command, request.path)
        return self._execute_handler_function(request, fun)

    def _pick_handler_function(self, command, path):
        key = command + path
        if key in self.urls:
            return self.urls[key]
        else:
            raise NoSuchUrl(key)

    def _execute_handler_function(self, request, fun):
        parameter_number = len(inspect.signature(fun).parameters)
        if parameter_number == 2:
            request.scheduler = self.scheduler
            request.deque = self.deque
            return fun(request, HTTPResponse())
        else:
            raise ArgumentLookupError(fun)


class ArgumentLookupError(Exception):
    def __init__(self, fun):
        self.fun = fun

    def __str__(self):
        return repr('cant find proper params in' + self.fun)

