RE_CELL = re.compile(r'\((.+?)\)')
RE_ATOM = re.compile(r'<\s*(\(.+?\))\s*>')
RE_TABLE = re.compile(
        r'\{-?(\d+):\^(..)\s*\{\(k\^(..):c\)\(s=9u?\)\s*(.*?)\}\s*(.+?)\}')
RE_ROW = re.compile(r'(-?)\s*\[(.+?)((\(.+?\)\s*)*)\]')
RE_CELL_TEXT = re.compile(r'\^(.+?)=(.*)')
RE_CELL_OID = re.compile(r'\^(.+?)\^(.+)')
RE_TRAN_BEGIN = re.compile(r'@\$\$\{.+?\{\@')
RE_TRAN_END = re.compile(r'@\$\$\}.+?\}\@')


COLS_TO_KEEP = (
        'DisplayName',
        'FirstName',
        'LastName',
        'PrimaryEmail',
        'SecondEmail',
)

SPECIAL_CHARS = (
        ('\\\\', '\\'),
        ('\\$', '$'),
        ('\\t', chr(9)),
        ('\\n', chr(10)),
)

RE_ESCAPED = re.compile(r'(\$[a-f0-9]{2})', re.IGNORECASE)
RE_ESCAPEDB = re.compile(rb'(\$[a-f0-9]{2})', re.IGNORECASE)
RE_HEADER = re.compile(r'// <!-- <mdb:mork:z v="(.*)"/> -->')


class _Table(object):
    def __init__(self, tableid):
        self.tableid = tableid
        self.rows = {}

    def __repr__(self):
        return 'Table %r: %r' % (self.tableid, self.rows)

    def add_cell(self, rowid, col, atom):
        if ':' in rowid:
            rowid = rowid.split(':')[0]
        row = self.rows.get(rowid)
        if not row:
            row = self.rows[rowid] = dict()
        row[col] = _unescape_data(atom)

    def del_row(self, rowid):
        if ':' in rowid:
            rowid = rowid.split(':')[0]
        if rowid in self.rows:
            del self.rows[rowid]


def _unescape_character(match):
    value = match.group()
    try:
        return chr(int(value[1:], 16))
    except ValueError:
        return value

def _unescape_byte(match):
    value = match.group()
    return bytes([int(value[1:], 16)])

def _unescape_data(instr):
    for src, dst in SPECIAL_CHARS:
        instr = instr.replace(src, dst)
    if RE_ESCAPED.search(instr) is not None:
        inbytes = instr.encode("utf-8")
        instr = RE_ESCAPEDB.sub(_unescape_byte, inbytes).decode("utf-8", "replace")
    return instr


def _read_mork(filename):
    ''' Read mork file, return tables from file '''
    data = []
    with open(filename, 'rt') as mfile:
        header = mfile.readline().strip()
        # check header
        if not RE_HEADER.match(header):
            pretty.print_debug(__name__, '_read_mork: header error', header)
            return {}
        for line in mfile.readlines():
            # remove blank lines and comments
            line = line.strip()
            if not line:
                continue
            # remove comments
            comments = line.find('// ')
            if comments > -1:
                line = line[:comments].strip()
            if line:
                data.append(line)
        data = ''.join(data)

    if not data:
        return {}

    data = data.replace('\\)', '$29')

    # decode data
    cells = {}
    atoms = {}
    tables = {}
    pos = 0
    active_trans = False
    while data:
        data = data[pos:].lstrip()
        if not data:
            break

        # cols
        match = RE_COLS.match(data)
        if match:
            for cell in RE_CELL.findall(match.group()):
                key, val = cell.split('=', 1)
                if val in COLS_TO_KEEP:  # skip necessary columns
                    cells[key] = val
            pos = match.span()[1]
            continue

        # atoms
        match = RE_ATOM.match(data)
        if match:
            for cell in RE_CELL.findall(match.group()):
                if '=' in cell:
                    key, val = cell.split('=', 1)
                    atoms[key] = val
            pos = match.span()[1]
            continue

        # tables
        match = RE_TABLE.match(data)
        if match:
            tableid = ':'.join(match.groups()[0:2])
            table = tables.get(tableid)
            if not table:
                table = tables[tableid] = _Table(tableid)
            for row in RE_ROW.findall(match.group()):
                tran, rowid = row[:2]
                if active_trans and rowid[0] == '-':
                    rowid = rowid[1:]
                    table.del_row(rowid)
                if not active_trans or tran != '-':
                    rowdata = row[2:]
                    for rowcell in rowdata:
                        if not rowcell:
                            continue
                        for cell in RE_CELL.findall(rowcell):
                            atom, col = None, None
                            cmatch = RE_CELL_TEXT.match(cell)
                            if cmatch:
                                col = cells.get(cmatch.group(1))
                                atom = cmatch.group(2)
                            else:
                                cmatch = RE_CELL_OID.match(cell)
                                if cmatch:
                                    col = cells.get(cmatch.group(1))
                                    atom = atoms.get(cmatch.group(2))
                            if col and atom:
                                table.add_cell(rowid, col, atom)
            pos = match.span()[1]
            continue

        # transaction
        match = RE_TRAN_BEGIN.match(data)
        if match:
            active_trans = True
            continue

        match = RE_TRAN_END.match(data)
        if match:
            tran = True
            continue

        # dangling rows
        match = RE_ROW.match(data)
        if match:
            row = match.groups()
            tran, rowid = row[:2]
            table = tables.get('1:80')  # bind to default table
            if rowid[0] == '-':
                rowid = rowid[1:]
                if table:
                    table.del_row(rowid)
            if tran != '-':
                rowdata = row[2:]
                if rowdata:
                    if not table:
                        table = tables['1:80'] = _Table('1:80')
                    for rowcell in rowdata:
                        if not rowcell:
                            continue
                        for cell in RE_CELL.findall(str(rowcell)):
                            atom, col = None, None
                            cmatch = RE_CELL_TEXT.match(cell)
                            if cmatch:
                                col = cells.get(cmatch.group(1))
                                atom = cmatch.group(2)
                            else:
                                cmatch = RE_CELL_OID.match(cell)
                                if cmatch:
                                    col = cells.get(cmatch.group(1))
                                    atom = atoms.get(cmatch.group(2))
                            if col and atom:
                                table.add_cell(rowid, col, atom)
            pos = match.span()[1]
            continue

        pos = 1
    return tables


def _mork2contacts(tables):
    ''' Get contacts from mork table prepared by _read_mork '''
    if not tables:
        return
    # get only default table
    table = tables.get('1:80')
    if table:
        for row in table.rows.values():
            display_name = row.get('DisplayName')
            if not display_name:
                first_name = row.get('FirstName', '')
                last_name = row.get('LastName', '')
                display_name = ' '.join((first_name, last_name))
            if display_name:
                display_name = display_name.strip()
            for key in ('PrimaryEmail', 'SecondEmail'):
                email = row.get(key)
                if email:
                    yield (display_name or email[:email.find('@')], email)


_ABOOK_CONTACTS_SQL = """
select
    (select value from properties
     where card = c.uid and name = 'FirstName'
    ) as FirstName,
    (select value from properties
     where card = c.uid and name = 'LastName'
    ) as LastName ,
    (select value from properties
     where card = c.uid and name = 'DisplayName'
    ) as DisplayName ,
    (select value from properties
     where card = c.uid and name = 'PrimaryEmail'
    ) as PrimaryEmail ,
    (select value from properties
     where card = c.uid and name = 'SecondEmail'
    ) as SecondEmail
from cards c
"""


def _load_abook_sqlite(filename):
    ''' Load contacts from abook.sqlite filename.

    Thunderbird (like firefox) lock database, so it mus be opened as immutable
    and read-only. Also changes may be not visible immediate - require close
    sqlite file by thunderbird.
    '''

    dbfpath = filename.replace("?", "%3f").replace("#", "%23")
    dbfpath = "file:" + dbfpath + "?immutable=1&mode=ro"

    for _ in range(2):
        try:
            pretty.print_debug(__name__, "_load_abook_sqlite load:", dbfpath)
            with closing(sqlite3.connect(dbfpath, uri=True, timeout=1)) as conn:
                cur = conn.cursor()
                cur.execute(_ABOOK_CONTACTS_SQL)
                for (first_name, last_name, display_name, primary_email,
                     second_email) in cur:
                    if not display_name:
                        display_name = ' '.join((first_name, last_name))
                    if display_name:
                        display_name = display_name.strip()
                    for email in (primary_email, second_email):
                        if email:
                            yield (display_name or email[:email.find('@')],
                                   email)
            return
        except sqlite3.Error as err:
            # Something is wrong with the database
            # wait short time and try again
            pretty.print_debug(__name__, "_load_abook_sqlite error:", str(err))
            time.sleep(1)


def get_addressbook_dirs():
    ''' Get path to addressbook file from default profile. '''
    for thome, tprofile in THUNDERBIRD_PROFILES:
        if os.path.isfile(tprofile):
            config = RawConfigParser()
            config.read(tprofile)
            for section in config.sections():
                if config.has_option(section, "Path"):
                    path = config.get(section, "Path")
                    if not os.path.isabs(path):
                        path = os.path.join(thome, path)
                    if os.path.isdir(path):
                        yield path


def get_addressbook_files():
    ''' Get full path to all Thunderbird address book files. '''
    for path in get_addressbook_dirs():
        pretty.print_debug(__name__, 'get_addressbook_files dir:', path)
        files = os.listdir(path)
        for filename in files:
            if filename.endswith('.mab'):
                fullpath = os.path.join(path, filename)
                if os.path.isfile(fullpath):
                    yield fullpath

        abook_filename = os.path.join(path, "abook.sqlite")
        if os.path.isfile(abook_filename):
            yield abook_filename


def get_contacts():
    ''' Get all contacts from all Thunderbird address books as
        ((contact name, contact email)) '''
    for abook in get_addressbook_files():
        pretty.print_debug(__name__, 'get_contacts:', abook)
        if abook.endswith("abook.sqlite"):
            try:
                yield from _load_abook_sqlite(abook)
            except Exception as err:
                pretty.print_error(__name__, 'get_contacts error', abook, err)
        else:
            try:
                tables = _read_mork(abook)
            except IOError as err:
                pretty.print_error(__name__, 'get_contacts error', abook, err)
            else:
                yield from _mork2contacts(tables)


if __name__ == '__main__':
    print('\n'.join(map(str, sorted(get_contacts()))))

import random
import traceback

import demistomock as demisto  # noqa: F401
import urllib3
from CommonServerPython import *  # noqa: F401

# Disable insecure warnings
urllib3.disable_warnings()


BASE_URL = 'https://api.chucknorris.io'

CATEGORIES = ['career', 'dev', 'history', 'money', 'movie', 'music', 'science', 'sport', 'travel']

CHUCK_NORRIS_NAMES = [
    'Chuck Norris',
    'ChuckNorris',
    'chuck norris',
    'Chuck norris',
]

DBOT_NAME = 'DBot'


def replace_to_user_name(joke) -> str:
    res = joke
    for name in CHUCK_NORRIS_NAMES:
        res = res.replace(name, DBOT_NAME)
    return res


class Client(BaseClient):
    def chuck_norris_random(self, category) -> Dict[str, Any]:
        return self._http_request(
            method='GET',
            url_suffix='/jokes/random',
            params={
                'category': category
            }
        )


def test_module(client: Client) -> str:
    dbot_fact(client, {})
    return 'ok'


def get_dbot_image_path() -> str:
    image_index = random.randint(1, 16)

    return 'https://raw.githubusercontent.com/demisto/content/9784db67bb70839f1122ff5753d66cefbe2ca0d1/' \
           f'Packs/DBotTruthBombs/doc_imgs/dbot{image_index}.png'


def get_readable_output(fact, image) -> str:
    return f'### {fact}\n![DBot Image]({image})'


def dbot_fact(client: Client, args: Dict[str, Any]) -> Any:
    category = args.get('category', random.choice(CATEGORIES)).lower()
    result = client.chuck_norris_random(category)
    value = result.get('value')

    fact = replace_to_user_name(value)
    image = get_dbot_image_path()

    return CommandResults(
        readable_output=get_readable_output(fact, image),
        raw_response={
            "fact": fact,
            "image": image
        }
    )


def main() -> None:
    params = demisto.params()
    command = demisto.command()
    demisto.debug(f'Command being called is {command}')
    try:
        verify_certificate = not params.get('insecure', False)
        proxy = params.get('proxy', False)

        client = Client(
            base_url=BASE_URL,
            verify=verify_certificate,
            proxy=proxy)

        if command == 'test-module':
            result = test_module(client)
            return_results(result)

        elif command == 'dbot-truth-bomb':
            return_results(dbot_fact(client, demisto.args()))

    # Log exceptions and return errors
    except Exception as e:
        demisto.error(traceback.format_exc())  # print the traceback
        return_error(f'Failed to execute {command} command.\nError:\n{str(e)}')


if __name__ in ('__main__', '__builtin__', 'builtins'):
    main()

