from Parameter import Parameter

class Command:
    def __init__(self, commandTag):
        protoTag = commandTag.find("proto")
        
        # First we need to extract the return type.
        returnTag = protoTag.find("ptype")

        if returnTag is None:
            self.returnType = protoTag.text.strip()
        else:
            self.returnType = returnTag.text

        # Now we extract the name
        self.name = protoTag.find("name").text[2:]

        # Now build the parameter list
        parameters = commandTag.findall("param")
        self.params = []

        for param in parameters:
            self.params.append(Parameter(param))

    def getReturnType(self):
        return self.returnType

    def getName(self):
        return self.name

    def getParameters(self):
        return self.params

    def getParametersNames(self):
        return ", ".join(map(Parameter.getName, self.params))
    
    def getParametersString(self):
        return ", ".join(map(Parameter.getDeclaration, self.params))
    
    def toHeader(self):
        return "{returnType} {name}({params}) noexcept".format(
                returnType = self.returnType,
                name = self.name,
                params = self.getParametersString()
            )

