#!/usr/bin/python3

class TNode:

    def __init__(self, children):
        self.children = children

    def is_leaf(self):
        return self.children is None

    def __repr__(self):
        return repr(self.children)


class PaTrie:

    def __init__(self):
        self.root = None

    def __contains__(self, word):
        cur = self.root
        if cur is None:
            return False

        i = 0
        while cur is not None and not cur.is_leaf():
            for label, child in cur.children.items():
                if len(label) == 0 and i < len(word):
                    continue

                if word[i:i + len(label)] == label:
                    cur = child
                    i += len(label)
                    break
            else:
                return False
        return i == len(word)

    def insert(self, word):
        cur = self.root
        if cur is None:
            self.root = TNode({ word: None })
            return

        i = 0
        while not cur.is_leaf():
            for label, child in cur.children.items():
                cl = self.common_prefix_len(word[i:], label)
                if cl:
                    if cl == len(label):
                        cur = child
                        i += len(label)
                        break

                    del cur.children[label]

                    cur.children[label[:cl]] = TNode({
                        label[cl:]: child,
                        word[i + cl:]: TNode(None),
                    })
                    return

            else:
                cur.children[word[i:]] = TNode(None)
                return

        cur.children = {
            "": TNode(None),
            word[i:]: TNode(None)
        }

    def __str__(self):
        s = []
        def _str(tnode, sofar, label, prepend):
            if tnode is None:
                return
            if tnode.is_leaf():
                if label:
                    s.append(prepend + "+ " + label)
                s.append(prepend + "  {"+sofar+"}")
            else:
                s.append(prepend + "+ " + label)
                for label, child in tnode.children.items():
                    _str(child, sofar + label, label, prepend + "  ")

        if self.root is not None:
            _str(self.root, "", "", "")

        return "\n".join(s)


    def common_prefix_len(self, a, b):
        i = 0
        for x, y in zip(a, b):
            if x == y:
                i += 1
            else:
                break
        return i


if __name__ == "__main__":
    t = PaTrie()
    words = "autobus", "auto", "abraka", "dabra", "abrakadabra", "honza", "honirna", "honicka", "hony", "ho", "h"
    for w in words:
        t.insert(w)
        print("AFTER INSERTING", w)
        print(t.root)
        print(t)
        print()

#!/usr/bin/python

import optparse
import os
import shutil
import subprocess
import sys

def num_cpus():
    # Use multiprocessing module, available in Python 2.6+
    try:
        import multiprocessing
        return multiprocessing.cpu_count()
    except (ImportError, NotImplementedError):
        pass

    # Get POSIX system config value for number of processors.
    posix_num_cpus = os.sysconf("SC_NPROCESSORS_ONLN")
    if posix_num_cpus != -1:
        return posix_num_cpus

    # Guess
    return 2

def install_dependencies(dependencies, output_dir):
    for dependency in dependencies:
        status = install_dependency(dependency, output_dir)
        if status:
            return status

def install_dependency(dependency_name, output_dir):
    return subprocess.call(
        ["tar -xzf " + dependency_name + "/*.tar.gz -C " + output_dir], shell=True)

def cmake_configure(src_dir, build_type, output_dir, cxx_compiler = None, cxxflags = None):
    if os.path.exists("build"):
        shutil.rmtree("build")
    os.mkdir("build")
    cmake_args = ["cmake",
                  "-D", "CMAKE_INSTALL_PREFIX=" + output_dir,
                  "-D", "CMAKE_BUILD_TYPE=" + build_type]
    if cxx_compiler:
        cmake_args.append("-D")
        cmake_args.append("CMAKE_CXX_COMPILER=" + cxx_compiler)
    if cxxflags:
        cmake_args.append("-D")
        cmake_args.append("CMAKE_CXX_FLAGS=" + cxxflags)

    cmake_args.append("../" + src_dir)
    cmake_command = " ".join(cmake_args)
    if os.path.exists('/opt/gcc_env.sh'):
        cmake_command = "source /opt/gcc_env.sh && " + cmake_command
    print cmake_command
    return subprocess.call(cmake_command, cwd="build", shell=True)

def make():
    return subprocess.call(["make",
        "-j" + str(num_cpus()),
        "-l" + str(2 * num_cpus()),
        ],
        cwd="build",
        env=ccache_env()
        )


def ccache_env():
    env = os.environ.copy()
    env['CCACHE_DIR'] = os.getcwd() + '/.ccache'
    return env


def run_tests():
    return subprocess.call(["ctest",
                            "--output-on-failure",
                            "-j" + str(num_cpus()),
                            "--test-load", str(4 * num_cpus()),
                            ],
                            cwd="build")

def main():
    parser = optparse.OptionParser()
    parser.add_option("--build_type", dest="build_type", default="RELEASE")
    parser.add_option("--compiler", dest="compiler")
    parser.add_option("--cxxflags", dest="cxxflags")
    parser.add_option("--output_dir", dest="output_dir", default="install")
    parser.add_option("--skiptests", dest="skiptests", action="store_true", default=False)

    (options, args) = parser.parse_args()
    # install deps for building
    status = install_dependencies(args, "/usr/local")
    if status:
        return status
    status = cmake_configure("",
                             options.build_type,
                             options.output_dir,
                             options.compiler,
                             options.cxxflags)
    if status:
        return status
    status = make()
    if status:
        return status
    if not options.skiptests:
        status = run_tests()
        if status:
            return status
    return 0

if __name__ == "__main__":
    sys.exit(main())

